-- Insert 36 new plyometrics exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min::int,
  d.sets::int, d.reps::int, d.work::int, d.rest::int, d.est::int,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Squat Jump to Stick', 'squat-jump-to-stick', 'The athlete performs a two-foot squat jump, lands in an athletic base, and holds the stick long enough for the coach to verify position.', 'INTERMEDIATE', 8, 3, 3, 20, 75, 100, 'Vertical jump with a paused landing that trains takeoff intent and clean force acceptance.', 'Primary subrole: jump_throw_explosive_power. Treat Squat Jump to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Vertical jump landing control', 'output', 'jump_throw_explosive_power', 'vertical_power_to_stick', '{"primary_joint_actions":["hip_extension","knee_extension","ankle_plantar_flexion","landing_absorption"],"primary_tissues":["quadriceps","glutes","calves","achilles_tendon"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":2}'::jsonb, '{"movement_description":"The athlete performs a two-foot squat jump, lands in an athletic base, and holds the stick long enough for the coach to verify position.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Squat Jump to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Lateral Hop to Stick', 'lateral-hop-to-stick', 'The athlete hops laterally from one leg or two legs to a target and holds a quiet landing before resetting.', 'INTERMEDIATE', 8, 3, 3, 20, 75, 100, 'Side-to-side hop with a stick that teaches frontal-plane braking and hip-knee-foot alignment.', 'Primary subrole: deceleration_cod_power. Treat Lateral Hop to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Lateral landing control', 'output', 'deceleration_cod_power', 'lateral_landing_deceleration', '{"primary_joint_actions":["frontal_plane_push_off","single_leg_landing_control","hip_abduction_control","ankle_stiffness"],"primary_tissues":["glutes","adductors","calves","quadriceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":2}'::jsonb, '{"movement_description":"The athlete hops laterally from one leg or two legs to a target and holds a quiet landing before resetting.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Lateral Hop to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Single-Leg Hop to Stick', 'single-leg-hop-to-stick', 'The athlete hops from one leg and lands on the same leg, holding the stick without knee collapse, trunk sway, or extra foot taps.', 'INTERMEDIATE', 8, 3, 3, 20, 90, 120, 'Single-leg hop and pause that trains unilateral propulsion, alignment, and braking confidence.', 'Primary subrole: deceleration_cod_power. Treat Single-Leg Hop to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Single-leg landing control', 'output', 'deceleration_cod_power', 'single_leg_hop_to_stick', '{"primary_joint_actions":["single_leg_takeoff","single_leg_landing_control","hip_extension","ankle_plantar_flexion"],"primary_tissues":["glutes","quadriceps","calves","achilles_tendon"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"The athlete hops from one leg and lands on the same leg, holding the stick without knee collapse, trunk sway, or extra foot taps.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Single-Leg Hop to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Depth Drop to Athletic Stick', 'depth-drop-to-athletic-stick', 'The athlete steps from a slightly higher box, lands in an athletic base, and holds the position without bounce or collapse.', 'INTERMEDIATE', 8, 3, 3, 20, 90, 120, 'Progressed box drop that builds confidence absorbing greater landing forces with clean positions.', 'Primary subrole: deceleration_cod_power. Treat Depth Drop to Athletic Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Higher-force landing preparation', 'output', 'deceleration_cod_power', 'depth_drop_to_stick', '{"primary_joint_actions":["controlled_step_off","rapid_landing_absorption","trunk_bracing","hip_knee_ankle_flexion"],"primary_tissues":["quadriceps","glutes","calves","achilles_tendon"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"The athlete steps from a slightly higher box, lands in an athletic base, and holds the position without bounce or collapse.","setup":["Choose a stable box height that supports fast, controlled mechanics rather than ego height.","Place the box on a non-slip surface with clear space to step down or decelerate.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Depth Drop to Athletic Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Star Hop to Stick', 'star-hop-to-stick', 'The athlete hops to targets arranged like a star or clock face and sticks each landing before moving to the next target.', 'INTERMEDIATE', 8, 3, 3, 20, 75, 100, 'Clock-face hop pattern that trains directional landing control and spatial awareness.', 'Primary subrole: deceleration_cod_power. Treat Star Hop to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Multi-directional landing control', 'output', 'deceleration_cod_power', 'multi_directional_landing_deceleration', '{"primary_joint_actions":["multi_directional_push_off","single_leg_or_two_leg_landing","hip_reorientation","ankle_stiffness"],"primary_tissues":["glutes","adductors","calves","quadriceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":2}'::jsonb, '{"movement_description":"The athlete hops to targets arranged like a star or clock face and sticks each landing before moving to the next target.","setup":["Place cones or soft markers so the athlete can complete the drill without reaching or twisting to survive the target.","Keep the lane clear for landing, reset, or sprint exit.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Star Hop to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('180 Jump to Stick', '180-jump-to-stick', 'The athlete jumps vertically, rotates 180 degrees in the air, and lands in a stable athletic base facing the opposite direction.', 'INTERMEDIATE', 8, 3, 3, 20, 75, 100, 'Vertical jump with a half-turn that trains air control, reorientation, and stable landing mechanics.', 'Primary subrole: jump_throw_explosive_power. Treat 180 Jump to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Rotational landing control', 'output', 'jump_throw_explosive_power', 'rotational_jump_to_stick', '{"primary_joint_actions":["vertical_takeoff","trunk_rotation_control","hip_reorientation","landing_absorption"],"primary_tissues":["glutes","quadriceps","calves","obliques"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":2}'::jsonb, '{"movement_description":"The athlete jumps vertically, rotates 180 degrees in the air, and lands in a stable athletic base facing the opposite direction.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for 180 Jump to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Skater Hop to Stick', 'skater-hop-to-stick', 'The athlete bounds laterally from one leg to the other and holds each landing before returning or continuing.', 'INTERMEDIATE', 8, 3, 3, 20, 90, 120, 'Side-to-side skating bound that develops lateral power and single-leg braking quality.', 'Primary subrole: deceleration_cod_power. Treat Skater Hop to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Lateral bound landing control', 'output', 'deceleration_cod_power', 'lateral_bound_to_stick', '{"primary_joint_actions":["lateral_push_off","single_leg_landing_control","hip_abduction_control","trunk_bracing"],"primary_tissues":["glutes","adductors","calves","quadriceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"The athlete bounds laterally from one leg to the other and holds each landing before returning or continuing.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Skater Hop to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Ankle Pogo in Place', 'ankle-pogo-in-place', 'The athlete performs small, quick two-foot bounces from the balls of the feet while staying tall and quiet.', 'INTERMEDIATE', 8, 2, 12, 10, 60, 75, 'Low-amplitude two-foot contacts that teach springy ankle stiffness and elastic rebound.', 'Primary subrole: elastic_stiffness_plyometric_rudiments. Treat Ankle Pogo in Place as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Elastic ankle stiffness', 'output', 'elastic_stiffness_plyometric_rudiments', 'ankle_stiffness_rudiments', '{"primary_joint_actions":["ankle_plantar_flexion","reactive_ground_contact","knee_stiffness"],"primary_tissues":["calves","achilles_tendon","foot_intrinsics"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":1}'::jsonb, '{"movement_description":"The athlete performs small, quick two-foot bounces from the balls of the feet while staying tall and quiet.","setup":["Use a flat, forgiving surface with enough space to land and reset.","Mark the start or target distance only as far as the athlete can control cleanly.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Ankle Pogo in Place with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast