  ('Lateral Cone Hop to Sprint', 'lateral-cone-hop-to-sprint', 'The athlete performs one or more lateral hops over a low cone, lands ready, then exits into a short sprint lane.', 'INTERMEDIATE', 8, 3, 3, 15, 90, 110, 'Lateral hop over a cone followed by a short sprint to connect frontal-plane stiffness with acceleration.', 'Primary subrole: reactive_agility_tumbling_output. Treat Lateral Cone Hop to Sprint as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Plyometric change-of-direction transfer', 'output', 'reactive_agility_tumbling_output', 'lateral_hop_to_sprint', '{"primary_joint_actions":["lateral_hop","hip_reorientation","acceleration_projection"],"primary_tissues":["glutes","adductors","calves","hamstrings"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"The athlete performs one or more lateral hops over a low cone, lands ready, then exits into a short sprint lane.","setup":["Place cones or soft markers so the athlete can complete the drill without reaching or twisting to survive the target.","Keep the lane clear for landing, reset, or sprint exit.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Lateral Cone Hop to Sprint with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('45-Degree Cut Bound to Stick', '45-degree-cut-bound-to-stick', 'The athlete bounds or hops at a 45-degree angle to a cone target, lands, and holds the position before resetting.', 'INTERMEDIATE', 8, 3, 3, 20, 90, 120, 'Diagonal bound to a controlled stick that trains angled projection and braking for change of direction.', 'Primary subrole: deceleration_cod_power. Treat 45-Degree Cut Bound to Stick as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Angled cut power', 'output', 'deceleration_cod_power', 'angled_cut_bound_to_stick', '{"primary_joint_actions":["diagonal_projection","hip_reorientation","single_leg_or_two_leg_braking"],"primary_tissues":["glutes","adductors","calves","quadriceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"The athlete bounds or hops at a 45-degree angle to a cone target, lands, and holds the position before resetting.","setup":["Place cones or soft markers so the athlete can complete the drill without reaching or twisting to survive the target.","Keep the lane clear for landing, reset, or sprint exit.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for 45-Degree Cut Bound to Stick with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Reactive Partner Mirror Hop', 'reactive-partner-mirror-hop', 'One athlete leads small hops or bounds inside a defined space while the partner mirrors direction and timing.', 'INTERMEDIATE', 8, 3, 3, 15, 90, 110, 'Partner-led hop drill that adds perception-action demand to low-to-moderate plyometric contacts.', 'Primary subrole: reactive_agility_tumbling_output. Treat Reactive Partner Mirror Hop as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Reactive plyometric agility', 'output', 'reactive_agility_tumbling_output', 'reactive_mirror_hop', '{"primary_joint_actions":["reactive_lateral_hop","visual_decision","single_leg_or_two_leg_landing"],"primary_tissues":["glutes","adductors","calves","quadriceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"single_leg_or_dynamic","coordination_demand":"high_speed_timing","impact_level":3}'::jsonb, '{"movement_description":"One athlete leads small hops or bounds inside a defined space while the partner mirrors direction and timing.","setup":["Place cones or soft markers so the athlete can complete the drill without reaching or twisting to survive the target.","Keep the lane clear for landing, reset, or sprint exit.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Reactive Partner Mirror Hop with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Incline Plyo Push-Up', 'incline-plyo-push-up', 'The athlete performs a push-up from an incline and pushes hard enough for the hands to unload slightly while maintaining a plank shape.', 'INTERMEDIATE', 8, 3, 3, 15, 90, 110, 'Reduced-load plyometric push-up that builds fast upper-body push-off and trunk stiffness.', 'Primary subrole: jump_throw_explosive_power. Treat Incline Plyo Push-Up as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Upper-body plyometric push', 'output', 'jump_throw_explosive_power', 'upper_body_power', '{"primary_joint_actions":["explosive_elbow_extension","shoulder_horizontal_push","hand_contact_absorption","trunk_bracing"],"primary_tissues":["pectorals","triceps","anterior_deltoids","wrist_flexors"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"athletic_base","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":1}'::jsonb, '{"movement_description":"The athlete performs a push-up from an incline and pushes hard enough for the hands to unload slightly while maintaining a plank shape.","setup":["Choose a stable box height that supports fast, controlled mechanics rather than ego height.","Place the box on a non-slip surface with clear space to step down or decelerate.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Incline Plyo Push-Up with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Fast off the floor.","Quiet feet.","Own the landing.","Tall through the crown.","Stop before sloppy."],"common_faults":["Chasing height, distance, or speed after landing quality drops.","Loud contacts or collapsing into the floor.","Knees diving inward or feet losing tripod pressure.","Rib flare, lumbar extension, or trunk folding to survive the rep.","Turning the drill into conditioning instead of high-quality output."]}'::jsonb),
  ('Medicine Ball Rotational Shot Put', 'medicine-ball-rotational-shot-put', 'The athlete stands side-on to a wall, loads the back hip, rotates through the hips and trunk, and throws the ball like a shot put.', 'INTERMEDIATE', 8, 3, 4, 15, 75, 95, 'Side-on rotational medicine-ball throw that trains ground-up sequencing and transverse-plane power.', 'Primary subrole: jump_throw_explosive_power. Treat Medicine Ball Rotational Shot Put as Output-phase plyometrics: high intent, low volume, full recovery, and strict stop rules. Do not convert it into a fatigue circuit.', 'Move fast, land quiet, and reset before the next rep. The rep only counts if you own the position.', 'Medicine ball rotational power', 'output', 'jump_throw_explosive_power', 'medicine_ball_power_rotational', '{"primary_joint_actions":["hip_rotation","trunk_rotation_transfer","rapid_push_release"],"primary_tissues":["glutes","obliques","pectorals","triceps"],"primary_motor_control_demands":["postural_stiffness","landing_or_contact_precision","reset_between_attempts"],"postural_shape":"organized_power_posture","breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high_speed_timing","impact_level":0}'::jsonb, '{"movement_description":"The athlete stands side-on to a wall, loads the back hip, rotates through the hips and trunk, and throws the ball like a shot put.","setup":["Choose a light medicine ball that can be thrown fast without trunk leakage.","Use a safe wall, open lane, or trained partner depending on the throw direction.","Confirm the athlete can demonstrate the lower-level landing or contact pattern without pain.","Set the expectation that quality, not fatigue, decides the set length."],"execution_steps":["Start in the position described for Medicine Ball Rotational Shot Put with posture organized and eyes steady.","Create a sharp but relaxed takeoff or contact, keeping the ribs, pelvis, and foot pressure controlled.","Land, rebound, throw, or exit exactly as prescribed without adding extra contacts or rushed steps.","Reset fully before the next rep so every attempt is fast, quiet, and technically repeatable."],"coach_cues":["Light ball, fast release.","Throw through the target.","Hips then hands.","Brace and finish tall.","Reset before the next rep."],"common_faults":["Using a ball that is too heavy for speed.","Leaking through the low back or ribs during the throw.","Rotating or pressing from the arms only instead of using the whole body.","Standing too close to the wall or throwing into an unsafe lane.","Rushing reps until release speed fades."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
CROSS JOIN public.facility f
ON CONFLICT (facility_id, slug) DO NOTHING;

