INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), 'primary', m.slot, pos.order_index,
  COALESCE(m.freshness_required, TRUE), COALESCE(m.fatigue_sensitivity, 5), COALESCE(m.fatigue_cost, 3),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 2), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('squat-jump-to-stick', 'output', 'vertical_power_to_stick', 5, TRUE, 5, 3, 1, 2, 'moderate'),
  ('lateral-hop-to-stick', 'output', 'lateral_landing_deceleration', 5, TRUE, 5, 3, 2, 2, 'moderate'),
  ('single-leg-hop-to-stick', 'output', 'single_leg_hop_to_stick', 5, TRUE, 5, 4, 3, 3, 'moderate'),
  ('depth-drop-to-athletic-stick', 'output', 'depth_drop_to_stick', 5, TRUE, 5, 4, 3, 3, 'moderate'),
  ('star-hop-to-stick', 'output', 'multi_directional_landing_deceleration', 5, TRUE, 5, 3, 3, 2, 'moderate'),
  ('180-jump-to-stick', 'output', 'rotational_jump_to_stick', 5, TRUE, 5, 3, 3, 2, 'moderate'),
  ('skater-hop-to-stick', 'output', 'lateral_bound_to_stick', 5, TRUE, 5, 4, 3, 3, 'moderate'),
  ('ankle-pogo-in-place', 'output', 'ankle_stiffness_rudiments', 5, TRUE, 5, 3, 1, 1, 'moderate'),
  ('line-pogo-forward-back', 'output', 'linear_pogo_stiffness', 5, TRUE, 5, 3, 2, 1, 'moderate'),
  ('line-pogo-side-to-side', 'output', 'lateral_pogo_stiffness', 5, TRUE, 5, 3, 2, 1, 'moderate'),
  ('split-stance-pogo', 'output', 'split_stance_pogo', 5, TRUE, 5, 3, 2, 1, 'moderate'),
  ('single-leg-pogo-in-place', 'output', 'single_leg_pogo_stiffness', 5, TRUE, 5, 3, 3, 2, 'moderate'),
  ('jump-rope-bounce', 'output', 'jump_rope_elastic_rhythm', 5, TRUE, 5, 3, 2, 1, 'moderate'),
  ('low-cone-pogo-series', 'output', 'low_cone_pogo_series', 5, TRUE, 5, 3, 2, 2, 'moderate'),
  ('fast-ankling-pogo-march', 'output', 'ankling_pogo_march', 5, TRUE, 5, 3, 2, 1, 'moderate'),
  ('a-skip-pogo-rhythm', 'output', 'a_skip_pogo_rhythm', 5, TRUE, 5, 3, 3, 1, 'moderate'),
  ('snap-down-to-pogo-rebound', 'output', 'snap_down_rebound_pogo', 5, TRUE, 5, 3, 3, 2, 'moderate'),
  ('tuck-jump-to-stick', 'output', 'vertical_power_air_control', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('low-cone-hop-to-stick', 'output', 'low_obstacle_jump_to_stick', 5, TRUE, 5, 3, 2, 2, 'high'),
  ('repeated-vertical-jump', 'output', 'repeated_vertical_jump', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('approach-vertical-jump', 'output', 'approach_vertical_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('kneeling-jump-to-stand', 'output', 'kneeling_jump_power', 5, TRUE, 5, 3, 4, 2, 'high'),
  ('step-up-jump', 'output', 'step_up_jump_power', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('switch-step-up-jump', 'output', 'switch_step_up_jump_power', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('repeated-broad-jump', 'output', 'repeated_horizontal_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('bound-to-stick', 'output', 'bound_to_stick', 5, TRUE, 5, 4, 3, 3, 'high'),
  ('power-skip-for-distance', 'output', 'sprint_transfer_horizontal_power', 5, TRUE, 5, 3, 3, 2, 'high'),
  ('three-hop-bound-series', 'output', 'three_hop_bound_series', 5, TRUE, 5, 5, 4, 4, 'high'),
  ('uphill-bound', 'output', 'uphill_bound_power', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('drop-jump', 'output', 'drop_jump_reactive', 5, TRUE, 5, 5, 4, 4, 'high'),
  ('low-box-rebound-jump', 'output', 'low_box_rebound_jump', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('lateral-cone-hop-to-sprint', 'output', 'lateral_hop_to_sprint', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('45-degree-cut-bound-to-stick', 'output', 'angled_cut_bound_to_stick', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('reactive-partner-mirror-hop', 'output', 'reactive_mirror_hop', 5, TRUE, 5, 4, 4, 3, 'high'),
  ('incline-plyo-push-up', 'output', 'upper_body_power', 5, TRUE, 5, 3, 3, 1, 'high'),
  ('medicine-ball-rotational-shot-put', 'output', 'medicine_ball_power_rotational', 5, TRUE, 5, 3, 3, 0, 'high')
) AS m(slug, phase_key, slot, fit_weight, freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling)
JOIN coaching.exercise e ON e.slug = m.slug
JOIN coaching.session_phase sp ON sp.key = m.phase_key
JOIN coaching.phase_order_slot pos ON pos.key = m.slot AND pos.phase_id = sp.id
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role, order_slot = EXCLUDED.order_slot, fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required, fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost, technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level, intensity_ceiling = EXCLUDED.intensity_ceiling;

