  ('tuck-jump-to-stick', FALSE, 3, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
  ('low-cone-hop-to-stick', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('repeated-vertical-jump', FALSE, 3, 24, TRUE, TRUE, TRUE, TRUE, FALSE),
